import './Hero.css';

const Hero = () => {
  // Generate enhanced meteor/comet particles
  const generateParticles = () => {
    const particles = [];
    
    // Add shooting stars (white meteors like in background)
    for (let i = 0; i < 8; i++) {
      particles.push(
        <div
          key={`shooting-star-${i}`}
          className="particle shooting-star"
          style={{
            top: `${10 + Math.random() * 60}%`,
            animationDelay: `${Math.random() * 6}s`,
            animationDuration: `${4 + Math.random() * 3}s`
          }}
        />
      );
    }
    
    // Add large cyan comets
    for (let i = 0; i < 5; i++) {
      particles.push(
        <div
          key={`comet-large-${i}`}
          className="particle comet-large"
          style={{
            top: `${20 + Math.random() * 40}%`,
            animationDelay: `${Math.random() * 8}s`,
            animationDuration: `${6 + Math.random() * 4}s`
          }}
        />
      );
    }
    
    // Add medium green comets
    for (let i = 0; i < 7; i++) {
      particles.push(
        <div
          key={`comet-medium-${i}`}
          className="particle comet-medium"
          style={{
            top: `${15 + Math.random() * 50}%`,
            animationDelay: `${Math.random() * 7}s`,
            animationDuration: `${5 + Math.random() * 3}s`
          }}
        />
      );
    }
    
    // Add twinkling stars scattered across the screen
    for (let i = 0; i < 25; i++) {
      particles.push(
        <div
          key={`star-${i}`}
          className="particle star"
          style={{
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`,
            animationDelay: `${Math.random() * 3}s`,
            animationDuration: `${2 + Math.random() * 4}s`
          }}
        />
      );
    }
    
    // Add small floating dots for ambient effect
    for (let i = 0; i < 15; i++) {
      particles.push(
        <div
          key={`dot-${i}`}
          className="particle dot"
          style={{
            top: `${30 + Math.random() * 40}%`,
            animationDelay: `${Math.random() * 10}s`,
            animationDuration: `${8 + Math.random() * 6}s`
          }}
        />
      );
    }
    
    return particles;
  };

  return (
    <section id="home" className="hero">      
      {/* Enhanced meteor/comet particle system */}
      <div className="hero-particles">
        {generateParticles()}
      </div>
      
      <div className="hero-content">
        <div className="hero-image">
          <div className="hero-image-container">
            <img 
              src="/portfolio_img.jpg" 
              alt="Sarthak" 
              className="hero-profile-image"
            />
          </div>
        </div>

        <div className="hero-text">
          <h1 className="hero-title">Hi, I'm <span className="highlight">Sarthak</span></h1>
          <h2 className="hero-subtitle">AI/ML Engineer & <span className="highlight-blue">Full-Stack Developer</span></h2>
          <p className="hero-description">
            Transforming ideas into intelligent solutions through code and creativity
          </p>
          
          <div className="hero-social">
            <a href="https://github.com/sarthak" className="social-link" aria-label="GitHub">
              <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="currentColor">
                <path d="M12 0C5.374 0 0 5.373 0 12 0 17.302 3.438 21.8 8.207 23.387c.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23A11.509 11.509 0 0112 5.803c1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.30.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576C20.566 21.797 24 17.3 24 12c0-6.627-5.373-12-12-12z"/>
              </svg>
            </a>
            <a href="https://linkedin.com/in/sarthak" className="social-link" aria-label="LinkedIn">
              <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="currentColor">
                <path d="M20.447 20.452h-3.554v-5.569c0-1.328-.027-3.037-1.852-3.037-1.853 0-2.136 1.445-2.136 2.939v5.667H9.351V9h3.414v1.561h.046c.477-.9 1.637-1.85 3.37-1.85 3.601 0 4.267 2.37 4.267 5.455v6.286zM5.337 7.433a2.062 2.062 0 01-2.063-2.065 2.064 2.064 0 112.063 2.065zm1.782 13.019H3.555V9h3.564v11.452zM22.225 0H1.771C.792 0 0 .774 0 1.729v20.542C0 23.227.792 24 1.771 24h20.451C23.2 24 24 23.227 24 22.271V1.729C24 .774 23.2 0 22.222 0h.003z"/>
              </svg>
            </a>
            <a href="mailto:sarthak@example.com" className="social-link" aria-label="Email">
              <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="currentColor">
                <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/>
                <polyline points="22,6 12,13 2,6" fill="none" stroke="currentColor" strokeWidth="2"/>
              </svg>
            </a>
          </div>

          <div className="hero-buttons">
            <a href="#about" className="btn btn-primary">Explore My Journey</a>
            <a href="/resume.pdf" className="btn btn-secondary" target="_blank" rel="noopener noreferrer">Download Resume</a>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
